   153	export function connectAtomicSelectors(health: Record<string, SelectorHealthEntry>): void {
   154	  for (const entry of Object.values(health)) entry.dependents = []
   155	  for (const [name, entry] of Object.entries(health)) {
   156	    for (const dependency of entry.dependencies) {
   157	      if (health[dependency]) health[dependency].dependents.push(name)
   158	    }
   159	  }
   160	  if (topologicalOrder(health).length !== Object.keys(health).length) {
   161	    throw new Error('[KEA] Circular dependency detected')
   162	  }
   163	}
