   165	function topologicalOrder(health: Record<string, SelectorHealthEntry>): string[] {
   166	  const remaining = new Map(Object.entries(health).map(([name, entry]) => [name, entry.dependencies.filter((d) => !!health[d]).length]))
   167	  const order: string[] = []
   168	  while (remaining.size) {
   169	    const next = [...remaining.entries()].filter(([, count]) => count === 0).map(([name]) => name)
   170	    if (!next.length) break
   171	    for (const name of next) {
   172	      remaining.delete(name)
   173	      order.push(name)
   174	      for (const dependent of health[name].dependents) remaining.set(dependent, (remaining.get(dependent) || 0) - 1)
   175	    }
   176	  }
   177	  return order
   178	}
